import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛愛 = (bi) => 菩薩坐身(bi, {
    胸瓔滴z: 30.0,
    臂(bi, 筆) {
        const { M, L, C, S, 骨, 衣, 細, 逸, 陰, 陽 } = 筆;
        // 上臂常勢；前臂先落（畫序：臂→箭→拳——箭在臂前、拳覆箭上）
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.0); });
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-4.9, 35.1], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        骨(() => 陰(() => 前臂(bi, 筆, [13.7, 40.1], [5.1, 35.4], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.4, 肘帽: true })));
        // 箭：短箭橫浮當胸（高於臂線，鏃羽乃不與臂纏），鏃右羽左
        衣(() => {
            M(-9.9, 33.55);
            L(8.0, 34.27);
            S();
            M(-9.9, 33.9);
            L(8.0, 34.62);
            S();
            // 鏃：柳葉之鋒（衣筆實勒），中脊一線
            M(8.0, 33.92);
            C(9.1, 33.97, 10.1, 34.22, 10.8, 34.58);
            S();
            M(8.0, 34.97);
            C(9.1, 35.02, 10.1, 34.87, 10.8, 34.58);
            S();
            細(() => { M(8.3, 34.44); L(10.2, 34.57); S(); });
            // 羽：三片斜羽，張上下而尾微翹
            for (const t of [0, 1, 2]) {
                const bx = -7.35 - t * 0.85;
                M(bx, 33.52 - t * 0.035);
                C(bx - 0.45, 32.85 - t * 0.035, bx - 0.95, 32.65 - t * 0.035, bx - 1.5, 32.82 - t * 0.035);
                S();
                M(bx, 33.88 - t * 0.035);
                C(bx - 0.45, 34.55 - t * 0.035, bx - 0.95, 34.75 - t * 0.035, bx - 1.5, 34.58 - t * 0.035);
                S();
            }
            // 筈：尾端一叉
            M(-10.85, 33.25);
            L(-9.95, 33.62);
            S();
            M(-10.85, 34.1);
            L(-9.95, 33.73);
            S();
        });
        // 拳覆箭上（蔽法自斷笴線）：尊右拳執箭端（畫面左），尊左拳執近鏃（畫面右）
        側拳(bi, -3.3, 33.9, 0.45, 1.05);
        側拳(bi, 3.5, 34.2, -0.45, 1.05, -1);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-7.0, 35.6, -6.4, 36.5, -7.0, 37.5], [-6.2, 35.4, -5.6, 36.3, -6.2, 37.3]], [-6.2, 36.4]);
            腕釧(bi, [[7.2, 35.9, 6.6, 36.8, 7.2, 37.8], [6.4, 35.7, 5.8, 36.6, 6.4, 37.6]], [6.4, 36.7]);
        });
    },
});
